func ExpandModelGlobPath(globs ...string) ([]string, error) {
    modelPaths := []string{}

    for _, g := range globs {
        filepaths, err := filepath.Glob(g)
        if err != nil {
            return nil, err
        }
        for _, p := range filepaths {
            modelPaths = append(modelPaths, p)
        }
    }

    return modelPaths, nil
}

